#include<cstdio>
using namespace std;

int main()
{
	int a[1001],n,i,maxn,mina;
	double t,s=0;
	scanf("%d",&n);
	scanf("%d",&a[1]);
	s=s+a[1];
	mina=a[1];
	maxn=a[1];
	for(i=2;i<=n;i++)
	{
		scanf("%d",&a[i]);
		s+=a[i];
		if(a[i]>maxn)
		maxn=a[i];
		if(a[i]<mina)
		mina=a[i];
	}
	t=(s-(mina+maxn))/(n-2);
	printf("%0.2lf",t);
	return 0;
}
